class Solution {
    public int[] validSequence(String word1, String word2) {
        int m = word1.length(), n = word2.length();
        int[] res = new int[n];
        int diff = 0, mismatch = -1;

        for (int i = 0; i < n; i++) {
            if (word1.charAt(i) != word2.charAt(i)) {
                if (diff == 2) return new int[0];
                diff++;
                mismatch = i;
            }
            res[i] = i;
        }

        if (diff == 1) {
            res[mismatch] = -1;
            for (int i = mismatch + 1; i < n; i++) {
                if (word1.charAt(i) == word2.charAt(mismatch)) {
                    res[mismatch] = i;
                    break;
                }
            }
            if (res[mismatch] == -1) return new int[0];
        } else if (diff == 0) {
            for (int i = 0; i < n; i++) {
                if (word1.charAt(i) != word2.charAt(i)) {
                    for (int j = 0; j < i; j++) {
                        if (word1.charAt(j) == word2.charAt(i)) {
                            res[i] = j;
                            break;
                        }
                    }
                    if (res[i] == i) {
                        for (int j = i + 1; j < n; j++) {
                            if (word1.charAt(j) == word2.charAt(i)) {
                                res[i] = j;
                                break;
                            }
                        }
                    }
                    if (res[i] == i) return new int[0];
                    break;
                }
            }
        }

        int[] ans = new int[n];
        int j = 0;
        for (int i = 0; i < n; i++) {
            if (res[i] != -1) ans[j++] = res[i];
        }
        int[] finalAns = new int[j];
        System.arraycopy(ans, 0, finalAns, 0, j);
        return finalAns;
    }
}
